import { useEffect } from 'react';
import { useTasksStore } from '../stores/useTasksStore';
import { TaskCard } from './TaskCard';
import { TaskStatus, TaskPriority } from '../types/task';

export const TaskList = () => {
    const { tasks, fetchTasks, filters, setFilters } = useTasksStore();

    useEffect(() => {
        fetchTasks(filters.status, filters.priority);
    }, [filters, fetchTasks]);

    return (
        <div className='space-y-4'>
            <div className='flex space-x-4'>
                <select
                    value={filters.status}
                    onChange={(e) => setFilters({ status: e.target.value as TaskStatus })}
                    className='p-2 border rounded'
                >
                    <option value=''>Tous les statuts</option>
                    <option value='todo'>À faire</option>
                    <option value='in_progress'>En cours</option>
                    <option value='done'>Terminé</option>
                </select>
                <select
                    value={filters.priority}
                    onChange={(e) => setFilters({ priority: e.target.value as TaskPriority })}
                    className='p-2 border rounded'
                >
                    <option value=''>Toutes les priorités</option>
                    <option value='low'>Faible</option>
                    <option value='medium'>Moyenne</option>
                    <option value='high'>Élevée</option>
                </select>
            </div>
            <div className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4'>
                {tasks.map((task) => (
                    <TaskCard key={task.id} task={task} />
                ))}
            </div>
        </div>
    );
};

AuthProvider.code:
import { createContext, useContext, useEffect, useReducer } from 'react';
import { api } from '../services/api';
import { useNavigate } from 'react-router-dom';

const AuthContext = createContext(null);

const initialState = {
    isAuthenticated: false,
    user: null,
    token: null,
};

function authReducer(state, action) {
    switch (action.type) {
        case 'LOGIN':
            return {
                ...state,
                isAuthenticated: true,
                user: action.payload.user,
                token: action.payload.token,
            };
        case 'LOGOUT':
            return initialState;
        default:
            return state;
    }
}

export const AuthProvider = ({ children }) => {
    const [state, dispatch] = useReducer(authReducer, initialState);
    const navigate = useNavigate();

    useEffect(() => {
        const token = localStorage.getItem('token');
        if (token) {
            api.defaults.headers.common['Authorization'] = `Bearer ${token}`;
            dispatch({ type: 'LOGIN', payload: { token } });
        }
    }, []);

    const login = async (email, password) => {
        const response = await api.post('/auth/login', { email, password });
        const { access_token } = response.data;
        localStorage.setItem('token', access_token);
        api.defaults.headers.common['Authorization'] = `Bearer ${access_token}`;
        dispatch({ type: 'LOGIN', payload: { token: access_token } });
        navigate('/dashboard');
    };

    const logout = () => {
        localStorage.removeItem('token');
        delete api.defaults.headers.common['Authorization'];
        dispatch({ type: 'LOGOUT' });
        navigate('/login');
    };

    return (
        <AuthContext.Provider value={{ ...state, login, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);

